function buildFetchOptions(method, data, token) {
  const options = {
    method,
    headers: {
      'Authorization': 'Bearer ' + token
    }
  };
  if (data && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
    options.headers['Content-Type'] = 'application/json';
    options.body = JSON.stringify(data);
  }
  return options;
}

